    private void btnSelesaiActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnSelesaiActionPerformed

    String nama = txtNama.getText().trim();
    String meja = txtMeja.getText().trim();

    
    if (nama.isEmpty() || meja.isEmpty()) {
        javax.swing.JOptionPane.showMessageDialog(this, "Tunggu dulu! Nama dan No Meja wajib diisi!");
        return; 
    }

    try {
        double totalHarga = Double.parseDouble(txtTotalHarga.getText());
        double uangBayar = Double.parseDouble(txtUangBayar.getText());

        if (uangBayar < totalHarga) {
            javax.swing.JOptionPane.showMessageDialog(this, "Maaf, uang bayar Anda kurang!");
        } else {
            
            double kembalian = uangBayar - totalHarga;
            txtKembalian.setText(String.valueOf(kembalian));
            
            String struk = "=== STRUK PESANAN ===\n"
                         + "Nama: " + nama + "\n"
                         + "Meja: " + meja + "\n"
                         + "Total Tagihan: Rp " + totalHarga + "\n"
                         + "Uang Bayar: Rp " + uangBayar + "\n"
                         + "Kembalian: Rp " + kembalian + "\n"
                         + "=====================";
            javax.swing.JOptionPane.showMessageDialog(this, struk);
        }
    } catch (NumberFormatException e) {
  
        javax.swing.JOptionPane.showMessageDialog(this, "Gunakan angka yang benar untuk kotak pembayaran!");
    }

    }//GEN-LAST:event_btnSelesaiActionPerformed

