    private void btnKeluarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnKeluarActionPerformed
       
    int jawaban = javax.swing.JOptionPane.showConfirmDialog(this, 
                  "Apakah Anda yakin ingin menutup aplikasi kasir ini?", 
                  "Konfirmasi Keluar", 
                  javax.swing.JOptionPane.YES_NO_OPTION);
                  
    if (jawaban == javax.swing.JOptionPane.YES_OPTION) {
        System.exit(0);
    }
    }//GEN-LAST:event_btnKeluarActionPerformed
public void setTotalMakanan(String nilai){
    txtMakanan.setText(nilai);
    hitungGrandTotal(); 
}

public void setTotalMinuman(String nilai){
    txtMinuman.setText(nilai);
    hitungGrandTotal(); 
}

private void hitungGrandTotal() {
    try {
        double makan = Double.parseDouble(txtMakanan.getText());
        double minum = Double.parseDouble(txtMinuman.getText());
        txtTotalHarga.setText(String.valueOf(makan + minum));
    } catch (Exception e) {
        txtTotalHarga.setText("0");
    }
}
    
